VALUES
  ('real-estate-moex-01232', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '計量模型分析法係指「蒐集相當數量具代表性之比較標的，透過計量模型分析，求出各主要影響價格因 素與比較標的價格二者之關係式，以推算各主要影響價格因素之調整率及調整額之方法。」請問應用時 應符合條件中，採迴歸分析者，其調整後判定係數不得低於多少？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01233', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '「考慮銀行定期存款利率、政府公債利率、不動產投資之風險性、貨幣變動狀況及不動產價格之變動趨 勢等因素，選擇最具一般性財貨之投資報酬率為基準，比較觀察該投資財貨與勘估標的個別特性之差 異，並就流通性、風險性、增值性及管理上之難易程度等因素加以比較決定之。」係指收益資本化率何 種方式？ 債務保障比率法  風險溢酬法  市場萃取法  有效總收入乘數法', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01234', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '若某房屋經濟耐用年數45年、經歷年數20年、殘餘價格率10%，於收益法估價時，等速折舊型，建物 價格日期當時價值未來每年折舊提存率為何？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01235', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列有關成本法耐用年數之敘述，何者正確？ 建物折舊額計算應以物理耐用年數為主 物理耐用年數指建物因功能或效益衰退至不值得使用所經歷之年數 經濟耐用年數指建物因自然耗損或外力破壞至結構脆弱而不堪使用所經歷之年數 建物之經歷年數大於其經濟耐用年數時，應重新調整經濟耐用年數', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01236', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則規定，公共設施用地及公共設施保留地之估價，是以何種估價方法為原則？ 土地開發分析法  收益法  折現現金流量分析法  比較法', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01237', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '勘估標的之營造或施工費之求取方法中，「以建築細部工程之各項目單價乘以該工程施工數量，並合計 之」之方法，係指何方法？ 淨計法    單位工程法 工程造價比較法    單位面積（或體積）比較法', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01238', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '某公寓1至4樓之單價分別為100、70、60、70萬元/坪，若全棟建物成本價格占全棟房地總價格比率為 30%，若以3樓為基準，1至4樓之樓層別效用比分別為下列何者？ 、70%、60%、70%  、70%、70%、60% 、117%、117%、100%  、117%、100%、117%', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01239', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '不動產估價技術規則第89條規定：「受有土壤或地下水污染之土地，應先估算其未受污染之正常價格， 再依據委託人提供之土壤污染檢測資料，考量該土壤或地下水污染之影響，並計算其地價減損額後，從 正常價格中扣除之，以其餘額為該宗地之價格。」假設受污染宗地，未受污染正常價格2,000萬元，經勘 估地價減損額500萬元，則受污染地價格多少？ 萬元  ,000萬元  ,500萬元  ,000萬元', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01240', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '某建物於10年前興建，重建成本500萬元，殘餘價格率4%、經濟耐用年數40年，請問等速折舊型之建 物成本價格為何？ 萬元  萬元  萬元  萬元', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01241', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '西門町某店面於3年前出租經營，到期擬續租，當年契約租金每年 200萬元，目前市場經濟租金每年可 達250萬元，若分析此租金上漲應有60%歸功於承租經營者，在必要費用不增加情況下，合理續租年租 金多少？ 萬元  萬元  萬元  萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
